import{_ as a,o as t,c as e,a2 as n}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"왜 지금 Hermes가 뜨는가","description":"","frontmatter":{},"headers":[],"relativePath":"hermes/analysis/popularity.md","filePath":"hermes/analysis/popularity.md","lastUpdated":1781092690000}'),l={name:"hermes/analysis/popularity.md"};function i(o,s,r,d,p,c){return t(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="왜-지금-hermes가-뜨는가" tabindex="-1">왜 지금 Hermes가 뜨는가 <a class="header-anchor" href="#왜-지금-hermes가-뜨는가" aria-label="Permalink to &quot;왜 지금 Hermes가 뜨는가&quot;">​</a></h1><div class="badge-box"><span class="badge-red">Trend Analysis</span><span class="badge-teal">2026 Q2</span><span class="badge-gold">53.1k Stars in 6주</span></div><blockquote><p>2026년 2월 공개된 Hermes Agent는 6주 만에 53,000개 이상의 GitHub 스타, 375명의 기여자, 7개 메이저 릴리스를 기록하며 오픈소스 AI 에이전트 생태계의 이목을 한 몸에 받고 있습니다. 이 페이지는 그 <strong>인기의 구조적 원인</strong>을 단순한 기능 나열이 아니라 시장·브랜드·타이밍·기술적 선택 네 축에서 분석합니다.</p></blockquote><h2 id="인기의-크기" tabindex="-1">인기의 크기 <a class="header-anchor" href="#인기의-크기" aria-label="Permalink to &quot;인기의 크기&quot;">​</a></h2><div class="stat-grid"><div class="stat-card"><div class="stat-number">53.1k</div><div class="stat-label">GitHub Stars</div></div><div class="stat-card"><div class="stat-number">375</div><div class="stat-label">Contributors</div></div><div class="stat-card"><div class="stat-number">7</div><div class="stat-label">Releases · 6주</div></div><div class="stat-card"><div class="stat-number">643+</div><div class="stat-label">Community Skills</div></div></div><p>비교 지점:</p><table tabindex="0"><thead><tr><th>프로젝트</th><th>스타</th><th>도달 기간</th><th style="text-align:center;">주당 스타 획득</th></tr></thead><tbody><tr><td><strong>Hermes Agent</strong></td><td>53.1k</td><td>6주</td><td style="text-align:center;"><strong>~8,850</strong></td></tr><tr><td>OpenClaw</td><td>345k</td><td>누적 (&gt;1년)</td><td style="text-align:center;">~5,000</td></tr><tr><td>AutoGPT (초기)</td><td>100k</td><td>첫 달</td><td style="text-align:center;">~25,000</td></tr><tr><td>LangChain (초기)</td><td>20k</td><td>첫 6주</td><td style="text-align:center;">~3,300</td></tr></tbody></table><p>AutoGPT의 2023년 초기 바이럴만큼은 아니지만, <strong>AI 에이전트 피로감</strong>이 짙어진 2026년 시장에서 이 성장 속도는 이례적입니다. OpenClaw와 Hermes를 <strong>보완재</strong>로 인식하는 커뮤니티 합의가 형성되고 있다는 점도 중요합니다 — 제로섬 경쟁이 아닙니다.</p><h2 id="원인-1-·-nous-research-브랜드-후광" tabindex="-1">원인 1 · Nous Research 브랜드 후광 <a class="header-anchor" href="#원인-1-·-nous-research-브랜드-후광" aria-label="Permalink to &quot;원인 1 · Nous Research 브랜드 후광&quot;">​</a></h2><div class="pull"> Hermes Agent가 완전히 새로운 조직에서 나왔다면 이 속도는 불가능했습니다. Nous Research는 이미 <strong>Hermes LLM 시리즈</strong>로 오픈소스 LLM 파인튜닝 커뮤니티에서 확고한 신뢰를 쌓아둔 상태였습니다. </div><h3 id="기존-자산" tabindex="-1">기존 자산 <a class="header-anchor" href="#기존-자산" aria-label="Permalink to &quot;기존 자산&quot;">​</a></h3><dl class="kv"><dt>Nous Hermes 모델 시리즈</dt><dd>Llama·Mistral 기반 파인튜닝으로 2023년부터 Hugging Face 다운로드 상위권</dd><dt>DPO·DSPO 연구</dt><dd>정렬·학습 기법 논문으로 연구자 커뮤니티 접점</dd><dt>Nous Portal</dt><dd>자체 모델 API 서비스, 이미 400+ 모델 서빙 인프라</dd><dt>Discord 커뮤니티</dt><dd>수만 명의 활성 연구자·개발자</dd><dt>WorldSim·여타 프로토타입</dt><dd>창의적 에이전트 실험으로 &quot;재미있는 것을 만드는 팀&quot;이라는 이미지</dd></dl><p>새 에이전트를 출시했을 때 <strong>&quot;또 하나의 LangChain 클론&quot;으로 의심받지 않고</strong> 커뮤니티가 즉시 &quot;이 사람들이 만들면 뭐가 달라도 다르겠지&quot;라는 기대로 반응했습니다. 릴리스 첫 주에 수천 스타가 쌓인 건 이 누적 신뢰의 결과입니다.</p><h3 id="브랜드-일관성" tabindex="-1">브랜드 일관성 <a class="header-anchor" href="#브랜드-일관성" aria-label="Permalink to &quot;브랜드 일관성&quot;">​</a></h3><p><code>Hermes</code> 이름을 모델→에이전트로 <strong>일관되게 확장</strong>한 것도 전략적입니다. 기존 Hermes 모델 사용자는 자연스럽게 &quot;Hermes Agent가 Hermes 모델을 쓰면 최적화되어 있겠지&quot; 기대했고, 실제로 Nous Portal이 400+ 모델을 무료/저가로 제공하면서 이 기대를 충족시켰습니다(v0.5.0·v0.8.0).</p><h2 id="원인-2-·-자기개선-이라는-선명한-포지셔닝" tabindex="-1">원인 2 · &quot;자기개선&quot;이라는 선명한 포지셔닝 <a class="header-anchor" href="#원인-2-·-자기개선-이라는-선명한-포지셔닝" aria-label="Permalink to &quot;원인 2 · &quot;자기개선&quot;이라는 선명한 포지셔닝&quot;">​</a></h2><p>기존 에이전트 프레임워크가 <strong>기능 나열</strong>로 자신을 설명했다면, Hermes는 한 문장으로 자신을 규정했습니다.</p><div class="pull"> &quot;The only agent with a built-in learning loop — it creates skills from experience, improves them during use, nudges itself to persist knowledge.&quot; </div><p>이 문장은 <strong>경쟁자를 자동으로 제외</strong>합니다:</p><div class="two-col"><div class="col-card"><h4>이 문장이 내포하는 것</h4><ul><li>쓸수록 더 좋아진다</li><li>반복 작업이 자동화된다</li><li>사용자별로 개인화된다</li><li>팀 지식이 축적된다</li><li>장기 투자 가치가 있다</li></ul></div><div class="col-card"><h4>이 문장이 말하는 경쟁자</h4><ul><li>Claude Code — 좋지만 학습 안 됨</li><li>Codex — 쓸 때마다 처음부터</li><li>AutoGPT — 무한 루프에 빠짐</li><li>CrewAI — 역할만 부여, 개선 없음</li><li>LangGraph — 그래프는 있으나 경험 축적 없음</li></ul></div></div><p>마케팅에서 가장 강력한 메시지는 **&quot;무엇이 아닌가&quot;**를 암묵적으로 말하는 것입니다. 학습 루프는 기술적 차별점일 뿐만 아니라 <strong>메시징의 차별점</strong>이었습니다.</p><h2 id="원인-3-·-2026년-초의-시장-공백" tabindex="-1">원인 3 · 2026년 초의 시장 공백 <a class="header-anchor" href="#원인-3-·-2026년-초의-시장-공백" aria-label="Permalink to &quot;원인 3 · 2026년 초의 시장 공백&quot;">​</a></h2><p>2025년 말부터 2026년 초는 AI 에이전트 시장이 **&quot;약속은 많고 실속은 적다&quot;**는 피로감에 빠진 시기였습니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2023 · AutoGPT 열풍       →  무한 루프, 비용 폭주, 결과 불안정</span></span>
<span class="line"><span>2024 · 에이전트 이론 확산    →  ReAct, CoT, 프롬프트 엔지니어링 포화</span></span>
<span class="line"><span>2025 · Claude Code / Codex →  IDE 밀착 성공, 하지만 벤더 lock-in</span></span>
<span class="line"><span>2025 말 · LangGraph / CrewAI →  프레임워크 복잡, 실무 격차</span></span>
<span class="line"><span>───────────────────────────────────</span></span>
<span class="line"><span>2026 Q1 · 요구사항 정리</span></span>
<span class="line"><span>  ✓ 실제 도구 실행 (마크다운 에이전트 말고)</span></span>
<span class="line"><span>  ✓ 오픈소스, 자체 호스팅 가능</span></span>
<span class="line"><span>  ✓ 모델 중립 (API 키 자유)</span></span>
<span class="line"><span>  ✓ 쓸수록 개선 (매번 처음부터 가르치기 피로)</span></span>
<span class="line"><span>  ✓ 프로덕션 수준 보안</span></span>
<span class="line"><span>  ✓ 15+ 메시징 플랫폼 (어디서든 접근)</span></span></code></pre></div><p>이 <strong>다섯 가지 요구를 동시에 만족하는 프레임워크가 없었습니다</strong>. Claude Code는 3·4·5를 놓치고, OpenClaw는 4를 놓치고, AutoGPT는 2·5를 놓치고, 상용 SaaS는 전부를 놓쳤습니다.</p><p>Hermes는 <strong>이 모든 요구를 한 번에 체크</strong>한 채로 등장했습니다. 6주 동안 53k 스타는 &quot;드디어 우리가 기다리던 것&quot;이라는 반응에 가깝습니다.</p><h2 id="원인-4-·-오픈소스-mit라는-전략적-선택" tabindex="-1">원인 4 · 오픈소스 + MIT라는 전략적 선택 <a class="header-anchor" href="#원인-4-·-오픈소스-mit라는-전략적-선택" aria-label="Permalink to &quot;원인 4 · 오픈소스 + MIT라는 전략적 선택&quot;">​</a></h2><p>상용 솔루션과 비교할 때 Hermes가 가진 <strong>구조적 이점</strong>:</p><h3 id="금전적-장벽-제거" tabindex="-1">금전적 장벽 제거 <a class="header-anchor" href="#금전적-장벽-제거" aria-label="Permalink to &quot;금전적 장벽 제거&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th style="text-align:center;">Claude Code</th><th style="text-align:center;">Codex</th><th style="text-align:center;"><strong>Hermes</strong></th></tr></thead><tbody><tr><td>기본 사용료</td><td style="text-align:center;">월 $20</td><td style="text-align:center;">월 $20</td><td style="text-align:center;"><strong>$0</strong></td></tr><tr><td>무료 플랜</td><td style="text-align:center;">제한적</td><td style="text-align:center;">제한적</td><td style="text-align:center;"><strong>완전 무료 + 선택적 유료 모델</strong></td></tr><tr><td>$5 VPS 실행</td><td style="text-align:center;">❌ Anthropic 인프라 필수</td><td style="text-align:center;">❌ OpenAI 인프라 필수</td><td style="text-align:center;"><strong>✅</strong></td></tr><tr><td>자체 호스팅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;"><strong>✅</strong></td></tr><tr><td>상업 사용</td><td style="text-align:center;">상용 라이선스</td><td style="text-align:center;">상용 라이선스</td><td style="text-align:center;"><strong>MIT — 무제한</strong></td></tr></tbody></table><p>학생·개인 개발자·스타트업이 <strong>첫날부터 시도해 볼 수 있는</strong> 이유가 여기 있습니다. 트위터·YouTube의 입문 튜토리얼이 폭발적으로 늘어난 것도 이 진입 장벽의 차이 때문입니다.</p><h3 id="모델-종속-탈출" tabindex="-1">모델 종속 탈출 <a class="header-anchor" href="#모델-종속-탈출" aria-label="Permalink to &quot;모델 종속 탈출&quot;">​</a></h3><p>Claude Code는 Claude만, Codex는 GPT만 쓸 수 있습니다. 2026년은 Gemini 2.0, Claude 4 Opus, GPT-5, Llama 4 등 <strong>매달 새 모델이 나오는 시기</strong>입니다. Hermes는 v0.2.0부터 200+ 모델 지원으로 시작해 v0.5.0에서 400+, v0.8.0에서 Gemini 네이티브까지 추가했습니다.</p><p>사용자는 **&quot;이번에 나온 모델을 바로 써볼 수 있다&quot;**는 이유만으로 Hermes를 씁니다. 이건 구조적이라 경쟁자가 쉽게 따라잡기 어렵습니다.</p><h2 id="원인-5-·-6주-7릴리스의-속도-신호" tabindex="-1">원인 5 · 6주 7릴리스의 속도 신호 <a class="header-anchor" href="#원인-5-·-6주-7릴리스의-속도-신호" aria-label="Permalink to &quot;원인 5 · 6주 7릴리스의 속도 신호&quot;">​</a></h2><p>오픈소스 프로젝트의 건강도는 릴리스 빈도에서 드러납니다.</p><div class="timeline"><div class="timeline-item"><strong>v0.2.0</strong> (2026-03-12) · 최초 공개, 216 PR, 63 contributors </div><div class="timeline-item"><strong>v0.3.0</strong> (2026-03-17) · 5일 후, 스트리밍 + 플러그인 </div><div class="timeline-item"><strong>v0.4.0</strong> (2026-03-23) · 6일 후, OpenAI API 서버 + 6개 플랫폼 </div><div class="timeline-item"><strong>v0.5.0</strong> (2026-03-28) · 5일 후, 공급망 하드닝 + HF </div><div class="timeline-item"><strong>v0.6.0</strong> (2026-03-30) · 2일 후, 프로파일 + MCP 서버 모드 </div><div class="timeline-item"><strong>v0.7.0</strong> (2026-04-03) · 4일 후, 복원력 + 플러그블 메모리 </div><div class="timeline-item"><strong>v0.8.0</strong> (2026-04-08) · 5일 후, 백그라운드 알림 + Gemini </div></div><p>릴리스 간격의 <strong>중앙값이 5일</strong>입니다. 이것이 커뮤니티에 보내는 신호:</p><ol><li><strong>이슈가 빠르게 반영된다</strong> — 보고한 버그가 다음 주에 고쳐짐</li><li><strong>프로젝트가 살아있다</strong> — &quot;유지보수 중단&quot; 리스크가 낮음</li><li><strong>방향성이 분명하다</strong> — 릴리스마다 코드네임이 있고 테마가 있음</li><li><strong>기여가 환영받는다</strong> — PR이 빠르게 머지됨</li></ol><p>특히 <strong>v0.5.0의 litellm 공급망 공격 대응 속도</strong>는 전설적이었습니다. 커뮤니티가 공격을 감지한 지 며칠 안에 litellm을 제거하고 해시 핀닝을 도입한 릴리스를 낸 것이 &quot;신뢰할 수 있는 팀&quot;이라는 이미지를 굳혔습니다. 자세한 것은 <a href="/hermes/advanced/security#supply-chain">보안 체계 · 공급망 하드닝</a> 참조.</p><h2 id="원인-6-·-스킬-생태계의-네트워크-효과" tabindex="-1">원인 6 · 스킬 생태계의 네트워크 효과 <a class="header-anchor" href="#원인-6-·-스킬-생태계의-네트워크-효과" aria-label="Permalink to &quot;원인 6 · 스킬 생태계의 네트워크 효과&quot;">​</a></h2><p>agentskills.io 허브가 <strong>진짜 네트워크 효과</strong>를 만들어내는 첫 에이전트 생태계입니다.</p><h3 id="어떻게-작동하는가" tabindex="-1">어떻게 작동하는가 <a class="header-anchor" href="#어떻게-작동하는가" aria-label="Permalink to &quot;어떻게 작동하는가&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자 A가 스킬 작성 · 배포</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    agentskills.io에 643+ 스킬 축적</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>사용자 B가 &quot;ECR 배포&quot; 검색 → A의 스킬 발견</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>B가 자기 맥락에 맞게 refine</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>A의 스킬에 refinement 반영 PR</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>원본이 점점 성숙해져 C, D, E에게도 가치</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>[더 많은 사용자 → 더 많은 스킬 → 더 많은 가치]</span></span></code></pre></div><p><strong>스킬이 쌓일수록 Hermes를 쓸 이유가 커집니다.</strong> 이것이 AutoGPT 같은 초기 프레임워크가 만들지 못한 구조적 moat입니다.</p><h3 id="오픈-표준이라는-똑똑한-선택" tabindex="-1">오픈 표준이라는 똑똑한 선택 <a class="header-anchor" href="#오픈-표준이라는-똑똑한-선택" aria-label="Permalink to &quot;오픈 표준이라는 똑똑한 선택&quot;">​</a></h3><p>agentskills.io는 Nous Research가 소유했지만 <strong>벤더 중립 오픈 표준</strong>으로 설계되었습니다. 이론적으로 다른 에이전트도 같은 스킬을 로드할 수 있습니다. 이 개방성이 역설적으로 Hermes로의 집중을 강화합니다 — &quot;나중에 다른 프레임워크로 옮겨도 내 스킬은 살아남는다&quot;는 심리적 안전감.</p><h2 id="원인-7-·-복합-플랫폼-접점의-첫-사례" tabindex="-1">원인 7 · 복합 플랫폼 접점의 첫 사례 <a class="header-anchor" href="#원인-7-·-복합-플랫폼-접점의-첫-사례" aria-label="Permalink to &quot;원인 7 · 복합 플랫폼 접점의 첫 사례&quot;">​</a></h2><p>Hermes 이전의 에이전트는 <strong>한 접점만</strong> 잘했습니다:</p><ul><li>Claude Code / Codex / Cursor — IDE만</li><li>AutoGPT — 웹만</li><li>CrewAI — API만</li><li>각종 Slack 봇 — Slack만</li></ul><p>Hermes는 <strong>v0.2.0 시점에 이미 6개 접점</strong>(Telegram, Discord, Slack, WhatsApp, Signal, Email)을 지원했고, v0.4.0에서 6개 더(DingTalk, SMS, Mattermost, Matrix, Webhook, OpenAI API)를 추가했습니다. v0.6.0에서 Feishu, WeCom까지.</p><h3 id="어디서든-같은-에이전트-의-힘" tabindex="-1">&quot;어디서든 같은 에이전트&quot;의 힘 <a class="header-anchor" href="#어디서든-같은-에이전트-의-힘" aria-label="Permalink to &quot;&quot;어디서든 같은 에이전트&quot;의 힘&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Telegram 출근길]  → &quot;어제 배포한 거 롤백해야 할 것 같아&quot;</span></span>
<span class="line"><span>[CLI 사무실]      → &quot;아까 얘기한 롤백 진행해줘&quot; [자동 컨텍스트 복원]</span></span>
<span class="line"><span>[Slack 팀 채널]  → &quot;@Hermes 롤백 상태 팀에 공유&quot;</span></span>
<span class="line"><span>[Email 저녁]      → 완료 리포트 수신</span></span></code></pre></div><p>이 시나리오는 <strong>한 번 경험하면 돌아갈 수 없습니다</strong>. 트위터와 YouTube에서 &quot;Telegram에서 Claude Code를 제어하는 법&quot; 같은 영상이 바이럴이 된 것은 이 경험의 <strong>체감 질이 달랐기 때문</strong>입니다.</p><h2 id="원인-8-·-프로덕션-수준-보안의-신호" tabindex="-1">원인 8 · 프로덕션 수준 보안의 신호 <a class="header-anchor" href="#원인-8-·-프로덕션-수준-보안의-신호" aria-label="Permalink to &quot;원인 8 · 프로덕션 수준 보안의 신호&quot;">​</a></h2><p>2025년 말 LangChain 계열의 보안 사고가 여러 건 있었습니다. 에이전트가 쉘 실행을 쉽게 할 수 있는 구조적 문제가 드러나면서 <strong>&quot;장난감에서 프로덕션으로&quot;</strong> 넘어가려면 보안이 필수라는 합의가 생겼습니다.</p><p>Hermes는 이 합의에 <strong>태생부터 맞춰져 있었습니다</strong>:</p><dl class="kv"><dt>다층 승인 게이트</dt><dd>도구별·매개변수별 정책, allowlist/denylist</dd><dt>실행 격리</dt><dd>Docker, Singularity, Modal 샌드박스 — read-only root, cap-drop, pids_limit</dd><dt>Tirith 사전 실행 스캐너</dt><dd>쉘 명령을 실행 전에 분석하여 위험 패턴 차단</dd><dt>공급망 하드닝</dt><dd>v0.5.0 해시 핀닝, v0.8.0 OSV 스캐닝</dd><dt>시크릿 유출 차단</dt><dd>v0.7.0 outbound URL·base64·프롬프트 주입 경로 스캔</dd><dt>자격 증명 디렉토리 보호</dt><dd>~/.aws, ~/.ssh, ~/.docker 자동 차단</dd><dt>SSRF·타이밍 공격 방어</dt><dd>v0.8.0 보안 패스</dd></dl><p>&quot;공개 인시던트가 보고된 적이 없다&quot;는 것이 큰 차별점입니다. 기업 사용자는 이 <strong>조용함</strong>에 안도합니다.</p><h2 id="원인-9-·-개발자-경험-dx-의-세부" tabindex="-1">원인 9 · 개발자 경험(DX)의 세부 <a class="header-anchor" href="#원인-9-·-개발자-경험-dx-의-세부" aria-label="Permalink to &quot;원인 9 · 개발자 경험(DX)의 세부&quot;">​</a></h2><p>기능표에 안 드러나지만 사용자가 체감하는 것:</p><h3 id="설치가-한-줄" tabindex="-1">설치가 한 줄 <a class="header-anchor" href="#설치가-한-줄" aria-label="Permalink to &quot;설치가 한 줄&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/NousResearch/hermes-agent/main/scripts/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>Python 버전, uv, Node.js 같은 의존성을 <strong>인스톨러가 자동으로</strong> 처리합니다. &quot;1분 안에 첫 대화&quot;가 가능합니다.</p><h3 id="tui의-완성도" tabindex="-1">TUI의 완성도 <a class="header-anchor" href="#tui의-완성도" aria-label="Permalink to &quot;TUI의 완성도&quot;">​</a></h3><ul><li>멀티라인 편집</li><li>슬래시 명령 자동완성</li><li>토큰 스트리밍 + 인터럽트</li><li>세션 히스토리 탐색</li><li>7개 내장 스킨</li></ul><p>prompt-toolkit 기반으로 <strong>터미널 경험이 현대 IDE에 밀리지 않는 수준</strong>입니다. 이것이 사용자가 &quot;또 하나의 CLI 에이전트&quot;가 아니라 &quot;쓸 만한 도구&quot;로 느끼게 하는 결정적 요소입니다.</p><h3 id="에러-메시지의-질" tabindex="-1">에러 메시지의 질 <a class="header-anchor" href="#에러-메시지의-질" aria-label="Permalink to &quot;에러 메시지의 질&quot;">​</a></h3><p>에러가 날 때 <strong>무엇이 잘못되었고 어떻게 고칠지</strong>를 Markdown 포맷으로 친절히 알려줍니다. <code>hermes doctor</code>는 환경을 진단하고 문제를 짚어줍니다. 이것도 기능표에 안 나오지만 <strong>이탈률을 크게 낮춥니다</strong>.</p><h3 id="마이그레이션-지원" tabindex="-1">마이그레이션 지원 <a class="header-anchor" href="#마이그레이션-지원" aria-label="Permalink to &quot;마이그레이션 지원&quot;">​</a></h3><p>v0.2.0 출시 당시 이미 OpenClaw에서의 자동 마이그레이션(<code>hermes claw migrate</code>)을 제공했습니다. 경쟁자 사용자를 <strong>친절하게 받아들이는 태도</strong>가 이민율을 높였습니다.</p><h2 id="원인-10-·-연구자·해커·기업의-삼각-수요" tabindex="-1">원인 10 · 연구자·해커·기업의 삼각 수요 <a class="header-anchor" href="#원인-10-·-연구자·해커·기업의-삼각-수요" aria-label="Permalink to &quot;원인 10 · 연구자·해커·기업의 삼각 수요&quot;">​</a></h2><p>한 오픈소스 프로젝트가 <strong>세 집단을 동시에 만족</strong>시키는 경우는 드뭅니다.</p><div class="two-col"><div class="col-card"><h4>연구자</h4><ul><li>배치 트라젝토리 생성</li><li>tinker-atropos RL 파이프라인</li><li>wandb 통합</li><li>On-Policy Distillation (v0.3.0)</li><li>Singularity HPC 지원</li><li>→ <strong>논문 실험용 최적</strong></li></ul></div><div class="col-card"><h4>해커·개인</h4><ul><li>$5 VPS 실행</li><li>15+ 메시징 플랫폼</li><li>크론 자동화</li><li>재미있는 스킬 공유</li><li>무료 MiMo v2 Pro (v0.8.0)</li><li>→ <strong>개인 비서로 최적</strong></li></ul></div></div><div class="two-col"><div class="col-card"><h4>기업·팀</h4><ul><li>Docker/Modal 격리</li><li>다층 보안</li><li>감사 로그 (v0.8.0 중앙 로깅)</li><li>MIT 라이선스</li><li>프로파일 격리 (v0.6.0)</li><li>→ <strong>PoC에 적합</strong></li></ul></div><div class="col-card"><h4>삼각 수요의 효과</h4><ul><li>연구자가 논문에 인용</li><li>해커가 튜토리얼 제작</li><li>기업이 블로그에 채택 사례</li><li>세 집단이 서로의 콘텐츠 소비</li><li>→ <strong>담론의 중심</strong></li></ul></div></div><p>LangChain이 초기에 만든 네트워크 효과가 <strong>연구자-해커 두 축</strong>이었다면, Hermes는 여기에 <strong>기업 축</strong>까지 더해 더 강한 멤버십을 만들고 있습니다.</p><h2 id="원인-11-·-복사-가능한-인기의-설계" tabindex="-1">원인 11 · &quot;복사 가능한&quot; 인기의 설계 <a class="header-anchor" href="#원인-11-·-복사-가능한-인기의-설계" aria-label="Permalink to &quot;원인 11 · &quot;복사 가능한&quot; 인기의 설계&quot;">​</a></h2><p>커뮤니티가 자발적으로 콘텐츠를 만들 <strong>템플릿</strong>을 Hermes는 의도적으로 제공했습니다.</p><h3 id="바이럴-가능한-데모-포맷" tabindex="-1">바이럴 가능한 데모 포맷 <a class="header-anchor" href="#바이럴-가능한-데모-포맷" aria-label="Permalink to &quot;바이럴 가능한 데모 포맷&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Telegram에서 Claude Code를 제어하기&quot;     → YouTube 튜토리얼</span></span>
<span class="line"><span>&quot;Hermes에게 아침 브리핑 받기&quot;             → Reddit 공유</span></span>
<span class="line"><span>&quot;깃허브 이슈 자동 트리아지하기&quot;             → 블로그 포스트</span></span>
<span class="line"><span>&quot;Docker 배포를 자연어로&quot;                  → Twitter 영상</span></span></code></pre></div><p>각 시나리오가 <strong>5분 영상</strong>으로 만들 수 있는 길이이고, <strong>즉각적 가치</strong>가 명확합니다. 크리에이터는 이런 아이디어를 찾기 어려운데, Hermes 공식 문서와 <code>agentskills.io</code>의 스킬 예제들이 <strong>콘텐츠 아이디어의 저수지</strong> 역할을 했습니다.</p><h3 id="인플루언서의-재미" tabindex="-1">인플루언서의 재미 <a class="header-anchor" href="#인플루언서의-재미" aria-label="Permalink to &quot;인플루언서의 재미&quot;">​</a></h3><p>Medium에 &quot;Telegram에서 Claude Code 제어하기&quot; 같은 글이 자발적으로 수십 편 올라온 것은 <strong>이 조합을 자랑하고 싶은 욕구</strong>를 자극했기 때문입니다. Hermes를 쓴다는 것 자체가 &quot;최신 트렌드를 안다&quot;는 신호가 되는 순간 바이럴이 시작됩니다.</p><h2 id="원인-12-·-openclaw와의-의도치-않은-시너지" tabindex="-1">원인 12 · OpenClaw와의 의도치 않은 시너지 <a class="header-anchor" href="#원인-12-·-openclaw와의-의도치-않은-시너지" aria-label="Permalink to &quot;원인 12 · OpenClaw와의 의도치 않은 시너지&quot;">​</a></h2><p>경쟁자로 시작했지만 <strong>보완재로 인식</strong>되면서 둘 다 이득을 봤습니다.</p><dl class="kv"><dt>OpenClaw의 강점</dt><dd>오케스트레이션, 플러그인 폭, 대규모 배포 성숙도</dd><dt>Hermes의 강점</dt><dd>학습 루프, 장기 메모리, 자기개선</dd><dt>커뮤니티 합의</dt><dd>&quot;Hermes가 OpenClaw를 대체하지 않는다. 둘은 다른 문제를 푼다&quot;</dd></dl><p>이 프레이밍이 굳어지면서 사용자는 <strong>둘 다 배우는 것을 정당화</strong>할 수 있게 되었습니다. 경쟁 관계였다면 한쪽 선택이 다른 쪽 버림이었겠지만, 보완 관계로 인식되면 <strong>두 커뮤니티가 서로를 키웁니다</strong>.</p><p>OpenClaw의 345k 스타는 Hermes의 53k 스타를 <strong>누르는</strong> 대신 <strong>정당화</strong>합니다 — &quot;OpenClaw가 이렇게 많이 쓰이는데, 그에 못지않은 Hermes도 써볼 가치가 있다&quot;는 논리가 성립합니다.</p><h2 id="원인-13-·-타이밍-ai-에이전트-하이프-사이클의-회복기" tabindex="-1">원인 13 · 타이밍: AI 에이전트 하이프 사이클의 회복기 <a class="header-anchor" href="#원인-13-·-타이밍-ai-에이전트-하이프-사이클의-회복기" aria-label="Permalink to &quot;원인 13 · 타이밍: AI 에이전트 하이프 사이클의 회복기&quot;">​</a></h2><p>Gartner의 하이프 사이클 관점에서 보면:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2023 ─ AutoGPT ── 혁신 촉발(Trigger)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>2024 ─ 과도한 기대(Peak of Inflated Expectations)</span></span>
<span class="line"><span>    &quot;에이전트가 모든 일을 해줄 것&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>2024 말 ─ 환멸의 골짜기(Trough of Disillusionment)</span></span>
<span class="line"><span>    &quot;에이전트는 아직 못 한다&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>2025 ─ 계몽의 경사(Slope of Enlightenment)</span></span>
<span class="line"><span>    &quot;구체적으로 이런 작업은 가능하다&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>2026 ─ 생산성의 고원(Plateau of Productivity) 진입</span></span>
<span class="line"><span>    ✓ Hermes, Claude Code, OpenClaw 같은 &quot;진짜 쓸 만한&quot; 도구들</span></span></code></pre></div><p>Hermes는 <strong>회복기의 첫 번째 우승자</strong>가 될 타이밍에 나왔습니다. 시장이 &quot;뭐가 진짜 쓸 만한지&quot; 다시 찾기 시작하는 순간, Nous Research의 브랜드 신뢰 + 명확한 차별점 + 오픈소스라는 조합이 <strong>잃을 게 없는 시도</strong>로 평가받았습니다.</p><h2 id="인기가-이어지는-조건" tabindex="-1">인기가 이어지는 조건 <a class="header-anchor" href="#인기가-이어지는-조건" aria-label="Permalink to &quot;인기가 이어지는 조건&quot;">​</a></h2><p>현재의 기세가 <strong>1년 이상 유지되려면</strong> 필요한 것들:</p><div class="tip custom-block"><p class="custom-block-title">지속 가능성 체크리스트</p><ul><li><strong>v1.0 안정화</strong> — API 브레이킹이 멈추면 엔터프라이즈 도입 가속</li><li><strong>엔터프라이즈 관리 콘솔</strong> — SSO, RBAC, 감사 리포트, 중앙 정책</li><li><strong>문서화 격차 해소</strong> — 현재 핵심 기능은 잘 설명되지만 운영 노하우가 부족</li><li><strong>스킬 마켓플레이스 수익화</strong> — 기여자에게 인센티브 제공</li><li><strong>일본·유럽 커뮤니티 확장</strong> — 현재 영어·중국어 중심</li><li><strong>보안 인시던트 제로 유지</strong> — 한 번의 큰 사고가 신뢰를 갉아먹음</li><li><strong>Nous Research의 조직 안정성</strong> — 핵심 메인테이너 번아웃 방지</li></ul></div><h2 id="인기가-꺾일-수-있는-시나리오" tabindex="-1">인기가 꺾일 수 있는 시나리오 <a class="header-anchor" href="#인기가-꺾일-수-있는-시나리오" aria-label="Permalink to &quot;인기가 꺾일 수 있는 시나리오&quot;">​</a></h2><p>반대로 놓치면 안 되는 리스크:</p><div class="warning custom-block"><p class="custom-block-title">주의해야 할 함정</p><ul><li><strong>빅테크의 네이티브 에이전트</strong> — Google Gemini Agent, OpenAI의 차세대 에이전트가 비슷한 수준으로 나올 가능성</li><li><strong>6주 릴리스 속도의 부작용</strong> — API 안정성 희생, 기존 사용자 피로</li><li><strong>909 이슈가 2,000으로</strong> — 트리아지 속도가 따라가지 못하면 신뢰 하락</li><li><strong>단일 조직 의존</strong> — Nous Research에 문제가 생기면 전체 타격</li><li><strong>과도한 추상화</strong> — 플러그인·스킬·MCP·프로파일이 새 사용자에게 혼란</li><li><strong>모델 제공자 정책 변경</strong> — OpenRouter·Anthropic의 약관 변경 리스크</li><li><strong>AutoGPT식 반짝 유행</strong> — 6개월 후 잊히는 시나리오</li></ul></div><h2 id="결론-hermes-인기는-구조적인가-일시적인가" tabindex="-1">결론: Hermes 인기는 구조적인가 일시적인가 <a class="header-anchor" href="#결론-hermes-인기는-구조적인가-일시적인가" aria-label="Permalink to &quot;결론: Hermes 인기는 구조적인가 일시적인가&quot;">​</a></h2><div class="pull"> 결론부터 말하면 <strong>구조적</strong>입니다. 지금 Hermes가 받고 있는 관심은 운이 아니라, 다섯 개의 독립적인 요인이 동시에 만나 만든 결과이며 그 중 서너 개는 쉽게 사라지지 않습니다. </div><p><strong>구조적 요인</strong> (쉽게 복제 불가):</p><ol><li>Nous Research 브랜드 신뢰</li><li>학습 루프라는 기술적 moat</li><li>agentskills.io 네트워크 효과</li><li>오픈소스 + MIT의 경제적 해자</li><li>6주 7릴리스가 쌓은 커뮤니티 기대</li></ol><p><strong>일시적 요인</strong> (경쟁자가 따라잡을 수 있음):</p><ol><li>시장 타이밍(빅테크 에이전트 출시로 상쇄 가능)</li><li>OpenClaw와의 보완재 프레이밍(경쟁이 격화되면 변함)</li><li>연구자·해커 커뮤니티의 초기 실험 열풍</li></ol><p>그래서 <strong>1–2년 관점</strong>에서는 Hermes가 안정적으로 성장할 가능성이 높고, <strong>3–5년 관점</strong>에서는 학습 루프와 스킬 생태계의 성숙도에 달렸습니다. 지금이 채택을 고민할 가장 좋은 타이밍이라는 판단은 이 분석에서 나옵니다.</p><hr><h2 id="한-장-요약" tabindex="-1">한 장 요약 <a class="header-anchor" href="#한-장-요약" aria-label="Permalink to &quot;한 장 요약&quot;">​</a></h2><dl class="kv"><dt>인기의 숫자</dt><dd>53.1k stars, 375 contributors, 7 releases — 모두 6주 안에</dd><dt>가장 큰 원인 3가지</dt><dd>① Nous Research 브랜드 후광 ② 학습 루프의 명확한 포지셔닝 ③ 2026 Q1 시장 공백과의 매칭</dd><dt>기술적 해자</dt><dd>학습 루프 + 스킬 생태계 + 모델 중립성 + 멀티 플랫폼</dd><dt>경제적 해자</dt><dd>MIT 라이선스 + $5 VPS 실행 + 무료 Nous Portal</dd><dt>신뢰 해자</dt><dd>v0.5.0 litellm 사건 신속 대응 + 조용한 보안 이력</dd><dt>유행 가능성</dt><dd>AutoGPT식 반짝 유행 &lt; 50%. 지속 성장 &gt; 70%</dd><dt>권고</dt><dd>지금 채택이 가장 큰 복리 효과. 늦을수록 학습 루프 이익이 축소</dd></dl><hr><div class="tip custom-block"><p class="custom-block-title">연결 문서</p><ul><li>전체 경쟁 지형 → <a href="/hermes/analysis/market-position">시장 포지셔닝</a></li><li>도입 의사결정 기준 → <a href="/hermes/analysis/conclusion">종합 평가 및 전망</a></li><li>릴리스별 기능 전개 → <a href="/hermes/whats-new/">최신 기능 &amp; 릴리스</a></li><li>학습 루프의 구체적 메커니즘 → <a href="/hermes/features/learning-loop">학습 루프</a></li></ul></div>`,110)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
